#!/bin/bash
set -euo pipefail
trap 'echo "ERROR: deploy failed at line $LINENO" >&2' ERR
docker build -t myapp . || { echo 'docker build failed'; exit 1; }
docker push myapp:latest || { echo 'docker push failed'; exit 1; }
ssh prod 'docker pull myapp:latest && docker-compose restart' || { echo 'remote restart failed'; exit 1; }
echo 'Deploy complete'
